 1	import * as React from 'react';
 2	import { useK8sGet } from '../hooks/use-k8sGet-hook';
 3	import { ConfigMapModel } from '../../models';
 4	import { K8sResourceKind } from '@openshift-console/dynamic-plugin-sdk';
 5	import { PAC_INFO, PIPELINE_NAMESPACE } from '../../consts';
 6	import { ClipboardCopy } from '@patternfly/react-core';
 7	
 8	const RepositoryWebhookURL = () => {
 9	  const [pac, loaded] = useK8sGet<K8sResourceKind>(
10	    ConfigMapModel,
11	    PAC_INFO,
12	    PIPELINE_NAMESPACE,
13	  );
14	  return (
15	    <>
16	      {loaded && (
17	        <ClipboardCopy isReadOnly hoverTip="Copy" clickTip="Copied">
18	          {pac?.data?.['controller-url']}
19	        </ClipboardCopy>
20	      )}
21	    </>
22	  );
23	};
24	
25	export default RepositoryWebhookURL;

